// Validate required fields and format notification message
const body = $input.first().json;

const type = body.type ?? null;
const client = body.client ?? 'Cliente';
const details = body.details ?? '';
const link = body.link ?? '';

if (!type) throw new Error('Missing required field: type');

// CopyZen brand voice: conversacional, profissional, sem spam
const templates = {
  proposal_ready: `🎯 *Proposta pronta para revisão!*

Cliente: ${client}
${details ? '
' + details : ''}${link ? '

🔗 ' + link : ''}

_Revise e aprove para continuar o pipeline._`,
  content_delivered: `✅ *Conteúdo entregue no Drive!*

Cliente: ${client}
${details ? '
' + details : ''}${link ? '

🔗 ' + link : ''}

_Pronto para sua revisão._`,
  funwheel_published: `🚀 *FunWheel publicado!*

Cliente: ${client}
${details ? '
' + details : ''}${link ? '

🔗 ' + link : ''}

_Acesse e teste o fluxo A-R-T._`,
  lead_captured: `🎉 *Novo lead capturado!*

Cliente: ${client}
${details ? '
' + details : ''}${link ? '

🔗 ' + link : ''}`,
  pipeline_error: `⚠️ *Erro no pipeline*

Cliente: ${client}
${details ? '
' + details : ''}${link ? '

🔗 ' + link : ''}

_Verificar logs._`,
};

const message = templates[type] ?? `📬 *Notificação CopyZen*

${details}`;

return [{
  json: {
    type,
    client,
    message,
    sent_at: new Date().toISOString(),
  }
}];
